18	/// Matrix multiply backed by MLX.
19	///
20	/// Shape rules match the CPU path:
21	/// - `[m, k] @ [k, n] -> [m, n]`
22	/// - `[m, k] @ [k]    -> [m]`
23	///
24	/// Labels propagate identically: the contraction axis (`a`'s last
25	/// dim vs `b`'s first dim) must agree when both sides are labeled,
26	/// and the surviving label list is `[a.labels[0], b.labels[1]]`
27	/// (matrix-matrix) or `[a.labels[0]]` (matrix-vector). See
28	/// `mlpl_array::DenseArray::matmul` for the authoritative spec.
29	///
30	/// MLX inputs go through the GPU/Accelerate path in fp32, so the
31	/// parity test in `tests/parity_tests.rs` is tolerance-bounded
32	/// (f32 round-trip error), not bit-for-bit.
33	pub fn matmul(a: &DenseArray, b: &DenseArray) -> Result<DenseArray, ArrayError> {
34	    let (m, k) = match a.shape().dims() {
35	        [m, k] => (*m, *k),
36	        _ => {
37	            return Err(ArrayError::RankMismatch {
38	                expected: 2,
39	                got: a.rank(),
40	            });
41	        }
42	    };
43	    let result_labels = matmul_labels(a, b)?;
44	    match b.shape().dims() {
45	        [k2, n] if *k2 == k => {
46	            let n = *n;
47	            let data = mlx_matmul_compute(a.data(), b.data(), &[m, k], &[k, n]);
48	            finalize(Shape::new(vec![m, n]), data, result_labels)
49	        }
50	        [k2] if *k2 == k => {
51	            let data = mlx_matmul_compute(a.data(), b.data(), &[m, k], &[k]);
52	            finalize(Shape::vector(m), data, result_labels)
53	        }
54	        _ => Err(ArrayError::ShapeMismatch {
55	            source: k,
56	            target: b.shape().dims().first().copied().unwrap_or(0),
57	        }),
58	    }
59	}
