61	/// Run the actual MLX matmul on two shape-validated f64 buffers.
62	///
63	/// Casts f64 -> f32 on the way in (MLX's GPU path is fp32) and
64	/// f32 -> f64 on the way out. The `.eval()` call forces MLX's
65	/// lazy graph so `as_slice` sees materialized data.
66	fn mlx_matmul_compute(a: &[f64], b: &[f64], a_dims: &[usize], b_dims: &[usize]) -> Vec<f64> {
67	    let a_f32: Vec<f32> = a.iter().map(|&x| x as f32).collect();
68	    let b_f32: Vec<f32> = b.iter().map(|&x| x as f32).collect();
69	    let a_shape: Vec<i32> = a_dims.iter().map(|&d| d as i32).collect();
70	    let b_shape: Vec<i32> = b_dims.iter().map(|&d| d as i32).collect();
71	    let a_mlx = MlxArray::from_slice(&a_f32, &a_shape);
72	    let b_mlx = MlxArray::from_slice(&b_f32, &b_shape);
73	    let c = a_mlx
74	        .matmul(&b_mlx)
75	        .expect("mlx matmul on pre-validated shapes should not fail");
76	    c.eval()
77	        .expect("mlx eval on pre-validated shapes should not fail");
78	    let out: &[f32] = c.as_slice();
79	    out.iter().map(|&x| x as f64).collect()
80	}
