82	/// Attach labels and wrap the computed data as a `DenseArray`.
83	fn finalize(
84	    shape: Shape,
85	    data: Vec<f64>,
86	    labels: Option<Vec<Option<String>>>,
87	) -> Result<DenseArray, ArrayError> {
88	    let array = DenseArray::new(shape, data)?;
89	    match labels {
90	        Some(lbls) => array.with_labels(lbls),
91	        None => Ok(array),
92	    }
93	}
