95	/// Compute the result labels for matmul, mirroring
96	/// `mlpl_array::ops::matmul_labels` byte-for-byte (Saga 11.5
97	/// Phase 3 semantics). Kept local rather than re-exported from
98	/// `mlpl-array` so the CPU crate's internal helper stays internal.
99	fn matmul_labels(
100	    a: &DenseArray,
101	    b: &DenseArray,
102	) -> Result<Option<Vec<Option<String>>>, ArrayError> {
103	    if a.labels().is_none() && b.labels().is_none() {
104	        return Ok(None);
105	    }
106	    let default_b = vec![None; b.rank()];
107	    let al: &[Option<String>] = a.labels().unwrap_or(&[None, None][..]);
108	    let bl: &[Option<String>] = b.labels().unwrap_or(default_b.as_slice());
109	    if let (Some(sa), Some(sb)) = (&al[1], &bl[0])
110	        && sa != sb
111	    {
112	        return Err(ArrayError::LabelMismatch {
113	            expected: al.to_vec(),
114	            actual: bl.to_vec(),
115	        });
116	    }
117	    let mut result = vec![al[0].clone()];
118	    if b.rank() == 2 {
119	        result.push(bl[1].clone());
120	    }
