1	//! MLPL runtime target crate (Saga: compile-to-rust).
2	//!
3	//! Compiled MLPL code -- emitted by the future `mlpl!` proc macro
4	//! and the `mlpl build` subcommand -- calls into this crate. It
5	//! re-exports the value and shape types from `mlpl-array` and
6	//! `mlpl-core`, and provides typed Rust signatures for a handful of
7	//! core primitives so the codegen can emit straight-line calls like
8	//! `mlpl_rt::iota(5)` and `mlpl_rt::reshape(&x, &[2, 3])?`.
9	//!
10	//! This crate deliberately does *not* depend on `mlpl-eval`,
11	//! `mlpl-runtime`, or `mlpl-parser`. Those crates are tooling;
12	//! compiled binaries link only against `mlpl-rt` so they never
13	//! carry a parser or an interpreter at runtime.
14	
15	mod array_lit;
16	mod error;
17	
18	pub use array_lit::array_lit;
19	pub use mlpl_array::{ArrayError, DenseArray, Shape};
20	pub use mlpl_core::LabeledShape;
21	
22	/// `iota(n)` -- the vector `[0, 1, ..., n-1]` as f64 values.
23	#[must_use]
24	pub fn iota(n: usize) -> DenseArray {
25	    let data: Vec<f64> = (0..n).map(|i| i as f64).collect();
26	    DenseArray::from_vec(data)
27	}
28	
29	/// `shape(a)` -- the dimension list of `a` as a rank-1 array.
