156	impl DenseArray {
157	    /// Matrix multiplication.
158	    ///
159	    /// - [m, k] * [k, n] -> [m, n]
160	    /// - [m, k] * [k] -> [m] (matrix-vector product)
161	    ///
162	    /// Label propagation (Saga 11.5 Phase 3): the contraction axis
163	    /// (`self`'s last dim against `other`'s first dim) must agree when
164	    /// both sides carry explicit labels. Result labels are the
165	    /// non-contracted dims: `[self.labels[0], other.labels[1]]` for
166	    /// matrix-matrix, `[self.labels[0]]` for matrix-vector. Unlabeled
167	    /// sides contribute `None` positions.
168	    pub fn matmul(&self, other: &DenseArray) -> Result<DenseArray, ArrayError> {
169	        let (m, k) = match self.shape().dims() {
170	            [m, k] => (*m, *k),
171	            _ => {
172	                return Err(ArrayError::RankMismatch {
173	                    expected: 2,
174	                    got: self.rank(),
175	                });
176	            }
177	        };
178	        let result_labels = matmul_labels(self, other)?;
179	        match other.shape().dims() {
180	            [k2, n] if *k2 == k => {
181	                let n = *n;
182	                let data: Vec<f64> = self
183	                    .data
184	                    .chunks(k)
185	                    .flat_map(|row| {
186	                        (0..n).map(move |j| {
187	                            row.iter()
188	                                .zip(other.data.chunks(n).map(|col| col[j]))
189	                                .map(|(a, b)| a * b)
190	                                .sum::<f64>()
191	                        })
192	                    })
193	                    .collect();
194	                Ok(DenseArray {
195	                    shape: Shape::new(vec![m, n]),
196	                    data,
197	                    labels: result_labels,
198	                })
199	            }
200	            [k2] if *k2 == k => {
201	                let data: Vec<f64> = self
202	                    .data
203	                    .chunks(k)
204	                    .map(|row| row.iter().zip(other.data.iter()).map(|(a, b)| a * b).sum())
205	                    .collect();
206	                Ok(DenseArray {
207	                    shape: Shape::vector(m),
208	                    data,
209	                    labels: result_labels,
210	                })
211	            }
212	            _ => Err(ArrayError::ShapeMismatch {
213	                source: k,
214	                target: other.shape().dims().first().copied().unwrap_or(0),
215	            }),
216	        }
217	    }
218	}
219	
220	impl DenseArray {
221	    /// Reduce along an axis using the given binary operation.
222	    ///
223	    /// Removes the specified axis from the shape. For example,
224	    /// a [2,3] array reduced along axis 0 produces a [3] result.
225	    pub fn reduce_axis(
226	        &self,
227	        axis: usize,
228	        identity: f64,
229	        op: fn(f64, f64) -> f64,
230	    ) -> Result<DenseArray, ArrayError> {
231	        let dims = self.shape().dims();
232	        if axis >= dims.len() {
233	            return Err(ArrayError::IndexOutOfBounds {
234	                axis,
235	                index: axis,
236	                size: dims.len(),
237	            });
238	        }
239	        let mut result_dims: Vec<usize> = dims.to_vec();
240	        result_dims.remove(axis);
241	        let result_shape = Shape::new(result_dims);
242	        let result_count = result_shape.elem_count();
243	        let mut result_data = vec![identity; result_count];
244	
245	        let strides = compute_strides(dims);
246	        let axis_size = dims[axis];
247	        let axis_stride = strides[axis];
248	
249	        for flat in 0..self.elem_count() {
250	            let result_flat = if axis_stride > 1 {
251	                let outer = flat / (axis_size * axis_stride);
252	                let inner = flat % axis_stride;
253	                outer * axis_stride + inner
254	            } else {
255	                flat / axis_size
256	            };
257	            result_data[result_flat] = op(result_data[result_flat], self.data[flat]);
258	        }
259	
260	        let labels = self.labels.as_ref().map(|lbls| {
261	            let mut out = lbls.clone();
262	            out.remove(axis);
263	            out
264	        });
265	        Ok(DenseArray {
266	            shape: result_shape,
267	            data: result_data,
268	            labels,
269	        })
270	    }
271	}
