273	impl DenseArray {
274	    /// Argmax along an axis. Returns an array with the given axis
275	    /// removed whose values are the indices (as f64) of the maxima.
276	    /// Ties go to the first occurrence.
277	    pub fn argmax_axis(&self, axis: usize) -> Result<DenseArray, ArrayError> {
278	        let dims = self.shape().dims();
279	        if axis >= dims.len() {
280	            return Err(ArrayError::IndexOutOfBounds {
281	                axis,
282	                index: axis,
283	                size: dims.len(),
284	            });
285	        }
286	        let mut result_dims: Vec<usize> = dims.to_vec();
287	        result_dims.remove(axis);
288	        let result_shape = Shape::new(result_dims);
289	        let result_count = result_shape.elem_count();
290	        let mut best_val = vec![f64::NEG_INFINITY; result_count];
291	        let mut best_idx = vec![0.0f64; result_count];
292	
293	        let strides = compute_strides(dims);
294	        let axis_size = dims[axis];
295	        let axis_stride = strides[axis];
296	
297	        for flat in 0..self.elem_count() {
298	            let result_flat = if axis_stride > 1 {
299	                let outer = flat / (axis_size * axis_stride);
300	                let inner = flat % axis_stride;
301	                outer * axis_stride + inner
302	            } else {
303	                flat / axis_size
304	            };
305	            // Recover axis index: (flat / axis_stride) % axis_size.
306	            let axis_idx = (flat / axis_stride) % axis_size;
307	            let v = self.data()[flat];
308	            if v > best_val[result_flat] {
309	                best_val[result_flat] = v;
310	                best_idx[result_flat] = axis_idx as f64;
311	            }
312	        }
313	
314	        let mut out = DenseArray::new(result_shape, best_idx)?;
315	        if let Some(lbls) = self.labels.as_ref() {
316	            let mut new_lbls = lbls.clone();
317	            new_lbls.remove(axis);
318	            out.labels = Some(new_lbls);
319	        }
320	        Ok(out)
321	    }
322	}
323	
324	/// Compute the result labels for a `matmul(a, b)`. The contraction
325	/// axis is `a`'s last dim vs `b`'s first dim; if both sides name it
326	/// and the names differ, raise `LabelMismatch`. Output labels are the
327	/// non-contracted dims. An unlabeled side contributes `None` at its
328	/// position, preserving partial labeling. If neither side is labeled,
329	/// the result is fully unlabeled. Saga 11.5 Phase 3.
330	fn matmul_labels(
331	    a: &DenseArray,
332	    b: &DenseArray,
333	) -> Result<Option<Vec<Option<String>>>, ArrayError> {
334	    if a.labels.is_none() && b.labels.is_none() {
335	        return Ok(None);
336	    }
337	    let default_b = vec![None; b.rank()];
338	    let al = a.labels.as_ref().map_or(&[None, None][..], Vec::as_slice);
339	    let bl = b
340	        .labels
341	        .as_ref()
342	        .map_or(default_b.as_slice(), Vec::as_slice);
343	    if let (Some(sa), Some(sb)) = (&al[1], &bl[0])
344	        && sa != sb
345	    {
346	        return Err(ArrayError::LabelMismatch {
347	            expected: al.to_vec(),
348	            actual: bl.to_vec(),
349	        });
350	    }
351	    let mut result = vec![al[0].clone()];
352	    if b.rank() == 2 {
353	        result.push(bl[1].clone());
354	    }
355	    Ok(Some(result))
356	}
357	
358	/// Compute the label list for the result of an elementwise op on two
359	/// arrays. Scalars contribute no labels, so the non-scalar side wins
360	/// unconditionally when one operand is rank 0. For non-scalar pairs,
361	/// two unlabeled sides stay unlabeled, a single labeled side carries
362	/// its labels through, and two labeled sides must agree or
363	/// `LabelMismatch` is returned. Saga 11.5 Phase 3.
364	fn merge_labels(a: &DenseArray, b: &DenseArray) -> Result<Option<Vec<Option<String>>>, ArrayError> {
365	    if a.rank() == 0 {
366	        return Ok(b.labels.clone());
367	    }
368	    if b.rank() == 0 {
369	        return Ok(a.labels.clone());
370	    }
371	    match (&a.labels, &b.labels) {
372	        (None, None) => Ok(None),
373	        (Some(l), None) | (None, Some(l)) => Ok(Some(l.clone())),
374	        (Some(la), Some(lb)) if la == lb => Ok(Some(la.clone())),
375	        (Some(la), Some(lb)) => Err(ArrayError::LabelMismatch {
376	            expected: la.clone(),
377	            actual: lb.clone(),
378	        }),
379	    }
380	}
381	
382	/// Compute strides for row-major layout.
383	fn compute_strides(dims: &[usize]) -> Vec<usize> {
384	    let mut strides = vec![1; dims.len()];
385	    for i in (0..dims.len().saturating_sub(1)).rev() {
386	        strides[i] = strides[i + 1] * dims[i + 1];
387	    }
388	    strides
389	}
