15	#[test]
16	fn iota_scalar_basis() {
17	    let v = iota(5);
18	    assert_eq!(v.shape(), &Shape::vector(5));
19	    assert_eq!(v.data(), &[0.0, 1.0, 2.0, 3.0, 4.0]);
20	}
