29	#[test]
30	fn shape_matches_dims() {
31	    let m = DenseArray::new(Shape::new(vec![2, 3]), vec![0.0; 6]).unwrap();
32	    assert_eq!(shape(&m).data(), &[2.0, 3.0]);
33	}
