36	fn rank_of_scalar_vector_matrix() {
37	    assert_eq!(rank(&DenseArray::from_scalar(7.0)).data(), &[0.0]);
38	    assert_eq!(rank(&DenseArray::from_vec(vec![1.0; 4])).data(), &[1.0]);
39	    let m = DenseArray::new(Shape::new(vec![2, 3]), vec![0.0; 6]).unwrap();
