#[cfg(all(target_os = "macos", target_arch = "aarch64", feature = "mlx"))]
mod shapes;

#[cfg(all(target_os = "macos", target_arch = "aarch64", feature = "mlx"))]
pub use activations::{exp, log, relu, sigmoid, tanh};
#[cfg(all(target_os = "macos", target_arch = "aarch64", feature = "mlx"))]
pub use elementwise::{add, div, mul, neg, sub};
#[cfg(all(target_os = "macos", target_arch = "aarch64", feature = "mlx"))]
pub use matmul::matmul;
#[cfg(all(target_os = "macos", target_arch = "aarch64", feature = "mlx"))]
pub use shapes::{reshape, transpose};

