/// `transpose(a)` -- reverse axis order and reorder data to
/// row-major. Labels reverse alongside axes.
pub fn transpose(a: &DenseArray) -> Result<DenseArray, ArrayError> {
    let dims = a.shape().dims();
    if dims.len() <= 1 {
        // Scalar/vector: MLX's transpose on rank <= 1 is a no-op;
        // match the CPU path's clone-on-identity shortcut and skip
        // the fp32 round trip entirely.
        return Ok(a.clone());
    }
    let new_dims: Vec<usize> = dims.iter().rev().copied().collect();
    let mlx = dense_to_mlx(a.data(), dims);
    let transposed = mlx.transpose().expect("mlx transpose on validated shape");
    let labels = a
        .labels()
        .map(|lbls| lbls.iter().rev().cloned().collect::<Vec<_>>());
    finalize(Shape::new(new_dims), mlx_to_dense_data(transposed), labels)
}

